import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.sqrt((p1[0] - p2[0])**2 + (p1[1] - p2[1])**2)

    num_customers = len(unvisited_customers)
    if num_customers == 0:
        return None

    min_time_to_reach = np.inf
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        if arrival_time > end_window:
            # Late arrival, consider the penalty cost
            penalty_time = arrival_time - end_window
        else:
            penalty_time = max(0, start_window - arrival_time)  # Waiting time if early

        total_effective_time = arrival_time + penalty_time

        # Evaluate the best option based on minimizing the time when the truck can start serving this customer or wait until service starts
        if total_effective_time < min_time_to_reach:
            min_time_to_reach = total_effective_time
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if len(unvisited_customers) == 0:
        return None

    end_of_day = max([tw[1] for tw in time_windows])
    remaining_time = end_of_day - current_time
    time_importance = (end_of_day / remaining_time) if remaining_time else float('inf')

    best_node = None
    best_score = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer_pos)
        travel_time = dist_to_customer / truck_speed
        projected_arrival = current_time + travel_time

        start_window, end_window = time_windows[idx]
        if projected_arrival < start_window:
            time_penalty = (start_window - projected_arrival) * time_importance * 2 # Higher importance as time runs out
        elif projected_arrival > end_window:
            time_penalty = (projected_arrival - end_window) * time_importance * 5 # Significantly penalize late arrivals more near day-end
        else:
            time_penalty = 0

        score = travel_time + time_penalty

        if score < best_score:
            best_score = score
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(a, b):
        return np.linalg.norm(a - b)

    if len(unvisited_customers) == 0:
        return None

    # Compute travel times to all customers
    travel_times = [distance(cur_truck_pos, cust) / truck_speed for cust in unvisited_customers]
    arrival_times = [current_time + tt for tt in travel_times]

    best_score = float('inf')
    best_node = None

    # Compute score for each customer based on urgency and proximity
    for idx, (arrival_time, (start_time, end_time)) in enumerate(zip(arrival_times, time_windows)):
        # Scores calculation considering time window urgency
        if arrival_time > end_time:
            time_penalty = (arrival_time - end_time) * 15  # Stronger penalty outside window
        elif arrival_time < start_time:
            time_penalty = (start_time - arrival_time) * 5  # Lesser penalty for waiting
        else:
            time_penalty = 0

        # Distance factor with moderate weight
        distance_penalty = distance(cur_truck_pos, unvisited_customers[idx]) * 2

        score = time_penalty + distance_penalty

        # Select the node with the lowest score
        if score < best_score:
            best_score = score
            best_node = idx

    return best_node
